.prefixCls {
  display: flex;
  width: 100%;
  background: var(--star-horse-background);
  border: 1px solid #eee;

  :deep(.scrollbar__view) {
    height: 100%;
  }

  .overflow-hidden {
    position: relative;
    overflow-x: hidden;
    flex: 1;
  }

  .tool {
    position: relative;
    display: flex;
    width: 35px;
    height: 35px;
    align-items: center;
    vertical-align: middle;
    border-right: 1px solid var(--star-horse-style);
    border-left: 1px solid var(--star-horse-style);

    &:hover {
      :deep(span) {
        color: #000000 !important;
      }
    }


  }

  .tags-item {
    position: relative;
    top: 3px;
    align-items: center;
    padding-right: 5px;
    margin-left: 4px;
    font-size: 12px;
    cursor: pointer;
    height: 100%;
    border: 1px solid #d9d9d9;
    display: inline-flex;

    .close-icon {
      position: relative;
      top: 35%;
      color: #333;
      display: none;
      transform: translate(0, -50%);
    }

    :not(.close-icon):hover {
      .close-icon {
        display: block;
      }
    }

    .tags {
      height: 28px;
      display: flex;
      position: relative;
      padding-left: 5px;
      right: 1px;
      vertical-align: middle;
      justify-content: center;
      align-items: center;
      white-space: nowrap;
    }
  }

  .tags-item:not(.is-active) {
    &:hover {
      color: var(--star-horse-style);
    }
  }

  .tags-item.is-active {
    color: var(--el-color-white);
    background-color: var(--star-horse-style);
    border: 1px solid var(--star-horse-style);

    :deep(.el-icon) {
      svg {
        color: var(--star-horse-white);
      }
    }

    .item--close {
      :deep(span) {

        color: var(--el-color-white) !important;
      }
    }
  }
}

